     8→
     9→/**
    10→ * A scorer that works in parallel.
    11→ */
    12→public class IdealParScoring extends AbstractDnaScoring {
    13→
    14→    private final int xLength;
    15→    private final int yLength;
    16→    private final int[][] s;
    17→
    18→    /**
    19→     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
    20→     * strands that they represent.
    21→     *
    22→     * @param args The names of two files.
    23→     */
    24→    public static void main(final String[] args) throws Exception {
    25→        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
    26→        scoringRunner.start("IdealParScoring", args);
    27→    }
    28→
    29→    /**
    30→     * Creates a new IdealParScoring.
    31→     *
    32→     * @param xLength length of the first sequence
    33→     * @param yLength length of the second sequence
    34→     */
    35→    public IdealParScoring(final int xLength, final int yLength) {
    36→        if (xLength <= 0 || yLength <= 0) {
    37→            throw new IllegalArgumentException(
    38→                "Lengths (" + xLength + ", " + yLength + ") must be positive!");
    39→        }
    40→        this.xLength = xLength;
    41→        this.yLength = yLength;
    42→        s = new int[xLength + 1][yLength + 1];
    43→
    44→        s[0][0] = 0;
    45→        for (int ii = 1; ii <= xLength; ii++) {
    46→            s[ii][0] = getScore(1, 0) * ii;
    47→        }
    48→        for (int jj = 1; jj <= yLength; jj++) {
    49→            s[0][jj] = getScore(0, 1) * jj;
    50→        }
    51→    }
    52→
    53→    /**
    54→     * This method should be filled in with a parallel implementation of the Smith-Waterman alignment algorithm that
    55→     * maximizes ideal parallelism.
    56→     * {@inheritDoc}
    57→     */
    58→    public int scoreSequences(final String x, final String y) throws SuspendableException {
    59→        // Process anti-diagonals: cells on the same anti-diagonal are independent.
    60→        // Anti-diagonal d: cells (i,j) where i+j = d.
    61→        // CPL = xLength + yLength - 1 (number of anti-diagonals).
    62→        // Work = xLength * yLength (one doWork(1) per cell).
    63→        for (int d = 2; d <= xLength + yLength; d++) {
    64→            final int dd = d;
    65→            finish(() -> {
    66→                final int iMin = Math.max(1, dd - yLength);
    67→                final int iMax = Math.min(xLength, dd - 1);
    68→                for (int i = iMin; i <= iMax; i++) {
    69→                    final int ii = i;
    70→                    final int jj = dd - ii;
    71→                    async(() -> {
    72→                        doWork(1);
    73→                        final char xc = x.charAt(ii - 1);
    74→                        final char yc = y.charAt(jj - 1);
    75→                        final int diagScore = s[ii - 1][jj - 1]
    76→                            + getScore(charMap(xc), charMap(yc));
    77→                        final int topScore = s[ii - 1][jj]
    78→                            + getScore(charMap(xc), 0);
    79→                        final int leftScore = s[ii][jj - 1]
    80→                            + getScore(0, charMap(yc));
    81→                        s[ii][jj] = Math.max(diagScore,
    82→                            Math.max(leftScore, topScore));
    83→                    });
    84→                }
    85→            });
    86→        }
    87→        return s[xLength][yLength];
    88→    }
    89→
    90→}
